 1	import React, { FC } from 'react';
 2	
 3	import { IoK8sApiNetworkingV1Ingress } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 4	import { Grid, GridItem, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 5	import Loading from '@utils/components/Loading/Loading';
 6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 7	import IngressDetailsSection from '@views/ingresses/details/tabs/details/components/IngressDetailsSection/IngressDetailsSection';
 8	
 9	import IngressRulesSection from './components/IngressRulesSection/IngressRulesSection';
10	
11	import './IngressDetailsTab.scss';
12	
13	type IngressDetailsTabProps = {
14	  obj: IoK8sApiNetworkingV1Ingress;
15	};
16	
17	const IngressDetailsTab: FC<IngressDetailsTabProps> = ({ obj: ingress }) => {
18	  const { t } = useNetworkingTranslation();
19	
20	  if (!ingress) return <Loading />;
21	
22	  return (
23	    <>
24	      <PageSection variant={PageSectionVariants.light}>
25	        <Title className="ingress-details-tab__header" headingLevel="h2">
26	          {t('{{kind}} details', { kind: ingress?.kind })}
27	        </Title>
28	        <Grid span={6}>
29	          <GridItem>
30	            <IngressDetailsSection ingress={ingress} />
31	          </GridItem>
32	        </Grid>
33	      </PageSection>
34	      <PageSection variant={PageSectionVariants.light}>
35	        <IngressRulesSection ingress={ingress} />
36	      </PageSection>
37	    </>
38	  );
39	};
40	
41	export default IngressDetailsTab;

